const body = $input.first().json.body;
const entry = body?.entry?.[0];
const change = entry?.changes?.[0];
const message = change?.value?.messages?.[0];

// Ignore delivery receipts and status updates
if (!message || message.type !== 'text') {
  return [];
}

return [{
  json: {
    userId: message.from,
    phone: message.from,
    text: message.text?.body?.trim() || '',
    messageType: message.type,
    timestamp: message.timestamp
  }
}];

const msgData = $('Extract Message').first().json;
const sessionRows = $input.first().json;

// Supabase returns an array; grab first row if exists
const existingSession = Array.isArray(sessionRows) && sessionRows.length > 0
  ? sessionRows[0].data
  : null;

const defaultSession = {
  state: 'TRIAGE',
  checkoutStep: null,
  collectedData: {},
  recommendedPackage: null,
  messageCount: 0,
  lastUpdated: new Date().toISOString()
};

const session = existingSession || defaultSession;

// Escalation guard
if (session.messageCount > 12 && session.state === 'TRIAGE') {
  session.state = 'ESCALATE';
}

return [{
  json: {
    userId: msgData.userId,
    phone: msgData.phone,
    text: msgData.text,
    session
  }
}];

const llmText = $input.first().json.text || '';
const prev = $('Build LLM Prompt').first().json;
const userText = prev.llmPayload?.userMessage?.toLowerCase() || '';
const session = prev.session || {};

// Detect booking intent from user's message
const bookingTriggers = [
  'yes', 'book', 'proceed', 'confirm', 'ok',
  'haan', 'ha', 'sure', 'please', 'go ahead',
  'sounds good', 'i want', 'book it', 'schedule'
];
const userWantsToBook = bookingTriggers.some(t => userText.includes(t));

// Extract which package the LLM recommended
let recommendedPackage = session.recommendedPackage;
if (llmText.includes('Deep Chart')) recommendedPackage = 'DEEP_CHART_ANALYSIS';
if (llmText.includes('Matchmaking')) recommendedPackage = 'MATCHMAKING';
if (llmText.includes('Muhurtham')) recommendedPackage = 'MUHURTHAM';

const messageCount = (session.messageCount || 0) + 1;

const updatedSession = {
  ...session,
  recommendedPackage,
  messageCount,
  state: userWantsToBook ? 'CHECKOUT' : 'TRIAGE',
  checkoutStep: userWantsToBook ? 'NAME' : null,
  lastUpdated: new Date().toISOString()
};

const replyText = userWantsToBook
  ? `Wonderful!  Let me get a few details to complete your booking.\n\nFirst, could you please share the name of the person the consultation is for?`
  : llmText;

return [{
  json: {
    userId: prev.userId,
    phone: prev.phone,
    text: prev.text,
    llmReply: llmText,
    replyText,
    userWantsToBook,
    session: updatedSession
  }
}];

const { text, session, userId, phone } = $input.first().json;
const step = session.checkoutStep;
const collected = { ...session.collectedData };

// Save the answer to the CURRENT step
if (step === 'NAME')        collected.name       = text;
if (step === 'DOB')         collected.dob        = text;
if (step === 'BIRTH_TIME')  collected.birthTime  = text;
if (step === 'BIRTH_PLACE') collected.birthPlace = text;

const steps = ['NAME', 'DOB', 'BIRTH_TIME', 'BIRTH_PLACE', 'DONE'];
const currentIndex = steps.indexOf(step);
const nextStep = steps[currentIndex + 1];
const isComplete = nextStep === 'DONE';

const prompts = {
  NAME:        `I am glad to help! \n\nFirst, could you please share the name of the person the consultation is for?`,
  DOB:         `Thank you! Could you share ${collected.name || 'their'}'s date of birth?\n(Example: 14 March 1995)`,
  BIRTH_TIME:  `Perfect. Do you know their exact time of birth?\nAn approximate time is absolutely fine too — like "morning" or "around 6 AM". `,
  BIRTH_PLACE: `Almost done!  Which city and state were they born in?`
};

let replyText;
if (isComplete) {
  const pkg = session.recommendedPackage || 'consultation';
  const pkgLabel = pkg === 'DEEP_CHART_ANALYSIS' ? 'Deep Chart Analysis'
    : pkg === 'MATCHMAKING' ? 'Matchmaking'
    : pkg === 'MUHURTHAM' ? 'Muhurtham' : 'Consultation';
  replyText = `Thank you so much! Here is a summary of your booking:\n\n Name: ${collected.name}\n Date of Birth: ${collected.dob}\n Time of Birth: ${collected.birthTime}\n Place of Birth: ${collected.birthPlace}\n Package: ${pkgLabel}\n\nPlease give me a moment while I generate your secure payment link... `;
} else {
  replyText = prompts[nextStep];
}

return [{
  json: {
    userId,
    phone,
    text,
    replyText,
    checkoutComplete: isComplete,
    session: {
      ...session,
      collectedData: collected,
      checkoutStep: isComplete ? 'DONE' : nextStep,
      state: isComplete ? 'PAYMENT_SENT' : 'CHECKOUT',
      lastUpdated: new Date().toISOString()
    }
  }
}];

const data = $('Checkout FSM').first().json;
const razorpayData = $input.first().json;

const pkg = data.session.recommendedPackage;
const pkgLabel = pkg === 'DEEP_CHART_ANALYSIS' ? 'Deep Chart Analysis'
  : pkg === 'MATCHMAKING' ? 'Matchmaking'
  : pkg === 'MUHURTHAM' ? 'Muhurtham' : 'Consultation';

const amount = pkg === 'DEEP_CHART_ANALYSIS' ? '₹2,999'
  : pkg === 'MATCHMAKING' ? '₹1,999' : '₹1,499';

const paymentUrl = razorpayData.short_url || razorpayData.id;

const replyText = ` *Payment Link Ready!*\n\nYour booking summary:\n ${data.session.collectedData.name}\n ${data.session.collectedData.dob}\n ${data.session.collectedData.birthTime}\n ${data.session.collectedData.birthPlace}\n ${pkgLabel} — ${amount}\n\nPlease complete your payment using the secure link below and your consultation will be confirmed right away. \n\n${paymentUrl}`;

return [{
  json: {
    ...data,
    replyText,
    paymentUrl,
    session: {
      ...data.session,
      state: 'PAYMENT_SENT',
      paymentUrl,
      lastUpdated: new Date().toISOString()
    }
  }
}];

const { phone, text, session, userId } = $input.first().json;

const replyText = `I completely understand, and I'm sorry you're going through this.  Let me connect you with our team directly for personalized assistance. Someone from AstroSharma will reach out to you very shortly.`;

return [{
  json: {
    userId,
    phone,
    text,
    replyText,
    alertMessage: `⚠️ AstroSharma — Human Handoff Needed\n\nUser: +${phone}\nLast message: "${text}"\nMessages sent: ${session.messageCount}\nPackage interest: ${session.recommendedPackage || 'Unknown'}\nSession state: ${session.state}`,
    session: {
      ...session,
      state: 'ESCALATE',
      lastUpdated: new Date().toISOString()
    }
  }
}];

const { phone, text, session, userId } = $input.first().json;
return [{
  json: {
    userId,
    phone,
    text,
    session,
    replyText: `Your payment link has already been shared above! \n\nPlease complete the payment and your booking will be confirmed right away. If you face any issues, our team is here to help.`
  }
}];

const data = $input.first().json;
return [{
  json: {
    userId: data.userId,
    phone: data.phone,
    replyText: data.replyText,
    session: data.session
  }
}];
